import { useState } from 'react'

interface UploadResult {
  key: string
  bucket: string
  filename: string
  size: number
  url: string
}

function FileUpload() {
  const [uploading, setUploading] = useState(false)
  const [result, setResult] = useState<UploadResult | null>(null)
  const [error, setError] = useState<string | null>(null)

  const handleFileUpload = async (file: File, bucket = 'default', key = '') => {
    setUploading(true)
    setError(null)

    const formData = new FormData()
    formData.append('file', file)
    formData.append('bucket', bucket)
    if (key) {
      formData.append('key', key)
    }

    try {
      const response = await fetch('http://localhost:7075/api/public/upload', {
        method: 'POST',
        body: formData
      })

      const data = await response.json()

      if (data.code === 200) {
        setResult(data.data)
      } else {
        setError(data.message || '上传失败')
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : '上传失败')
    } finally {
      setUploading(false)
    }
  }

  return (
    <div>
      <input
        type="file"
        onChange={(e) => {
          const file = e.target.files?.[0]
          if (file) {
            handleFileUpload(file)
          }
        }}
        disabled={uploading}
      />
      {uploading && <p>上传中...</p>}
      {error && <p style={{ color: 'red' }}>错误: {error}</p>}
      {result && (
        <div>
          <p>上传成功！</p>
          <p>文件URL: <a href={result.url}>{result.url}</a></p>
        </div>
      )}
    </div>
  )
}

export default FileUpload

import axios from 'axios'

async function uploadFileWithAxios(file, bucket = 'default', key = '') {
  const formData = new FormData()
  formData.append('file', file)
  formData.append('bucket', bucket)
  if (key) {
    formData.append('key', key)
  }

  try {
    const response = await axios.post(
      'http://localhost:7075/api/public/upload',
      formData,
      {
        headers: {
          'Content-Type': 'multipart/form-data'
        },
        onUploadProgress: (progressEvent) => {
          const percentCompleted = Math.round(
            (progressEvent.loaded * 100) / progressEvent.total
          )
          console.log(`上传进度: ${percentCompleted}%`)
        }
      }
    )

    if (response.data.code === 200) {
      return response.data.data
    } else {
      throw new Error(response.data.message)
    }
  } catch (error) {
    console.error('上传失败:', error)
    throw error
  }
}

import cn.hutool.core.io.FileUtil;
import cn.hutool.http.HttpRequest;
import cn.hutool.http.HttpResponse;
import cn.hutool.json.JSONObject;
import cn.hutool.json.JSONUtil;
import java.io.File;

public class FileUploadClient {
    private static final String UPLOAD_URL = "http://localhost:7075/api/public/upload";

    /**
     * 上传文件
     * @param filePath 文件路径
     * @param bucket 存储桶名称（可选，默认为 default）
     * @param key 文件存储路径（可选）
     * @return 上传结果
     */
    public static UploadResult uploadFile(String filePath, String bucket, String key) {
        File file = new File(filePath);
        if (!file.exists()) {
            throw new RuntimeException("文件不存在: " + filePath);
        }

        try {
            HttpRequest request = HttpRequest.post(UPLOAD_URL)
                    .form("file", file);

            // 添加可选参数
            if (bucket != null && !bucket.isEmpty()) {
                request.form("bucket", bucket);
            }
            if (key != null && !key.isEmpty()) {
                request.form("key", key);
            }

            HttpResponse response = request.execute();

            if (response.getStatus() == 200) {
                JSONObject json = JSONUtil.parseObj(response.body());
                if (json.getInt("code") == 200) {
                    JSONObject data = json.getJSONObject("data");
                    UploadResult result = new UploadResult();
                    result.setKey(data.getStr("key"));
                    result.setBucket(data.getStr("bucket"));
                    result.setFilename(data.getStr("filename"));
                    result.setSize(data.getLong("size"));
                    result.setUrl(data.getStr("url"));
                    return result;
                } else {
                    throw new RuntimeException("上传失败: " + json.getStr("message"));
                }
            } else {
                throw new RuntimeException("HTTP 请求失败，状态码: " + response.getStatus());
            }
        } catch (Exception e) {
            throw new RuntimeException("上传文件失败", e);
        }
    }

    /**
     * 上传文件（带文件类型限制）
     */
    public static UploadResult uploadFileWithTypeLimit(String filePath, String[] allowedTypes) {
        File file = new File(filePath);

        // 构建 URL，添加文件类型限制参数
        StringBuilder url = new StringBuilder(UPLOAD_URL);
        if (allowedTypes != null && allowedTypes.length > 0) {
            url.append("?");
            for (int i = 0; i < allowedTypes.length; i++) {
                if (i > 0) url.append("&");
                url.append("allowedTypes=").append(allowedTypes[i]);
            }
        }

        HttpRequest request = HttpRequest.post(url.toString())
                .form("file", file);

        HttpResponse response = request.execute();
        JSONObject json = JSONUtil.parseObj(response.body());

        if (json.getInt("code") == 200) {
            JSONObject data = json.getJSONObject("data");
            UploadResult result = new UploadResult();
            result.setKey(data.getStr("key"));
            result.setBucket(data.getStr("bucket"));
            result.setFilename(data.getStr("filename"));
            result.setSize(data.getLong("size"));
            result.setUrl(data.getStr("url"));
            return result;
        } else {
            throw new RuntimeException("上传失败: " + json.getStr("message"));
        }
    }

    // 使用示例
    public static void main(String[] args) {
        try {
            // 基础上传
            UploadResult result = uploadFile("/path/to/file.jpg", "default", "my-files/example.jpg");
            System.out.println("上传成功，文件URL: " + result.getUrl());

            // 带文件类型限制的上传
            UploadResult result2 = uploadFileWithTypeLimit("/path/to/image.png", 
                    new String[]{"jpg", "png"});
            System.out.println("上传成功，文件URL: " + result2.getUrl());
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

// 上传结果类
class UploadResult {
    private String key;
    private String bucket;
    private String filename;
    private Long size;
    private String url;

    // Getters and Setters
    public String getKey() { return key; }
    public void setKey(String key) { this.key = key; }
    public String getBucket() { return bucket; }
    public void setBucket(String bucket) { this.bucket = bucket; }
    public String getFilename() { return filename; }
    public void setFilename(String filename) { this.filename = filename; }
    public Long getSize() { return size; }
    public void setSize(Long size) { this.size = size; }
    public String getUrl() { return url; }
    public void setUrl(String url) { this.url = url; }
}

package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"mime/multipart"
	"net/http"
	"os"
	"path/filepath"
)

type UploadResult struct {
	Key      string `json:"key"`
	Bucket   string `json:"bucket"`
	Filename string `json:"filename"`
	Size     int64  `json:"size"`
	URL      string `json:"url"`
}

type UploadResponse struct {
	Code    int          `json:"code"`
	Message string       `json:"message"`
	Data    UploadResult `json:"data"`
}

// UploadFile 上传文件到 LingStorage
func UploadFile(filePath string, bucket string, key string) (*UploadResult, error) {
	// 打开文件
	file, err := os.Open(filePath)
	if err != nil {
		return nil, fmt.Errorf("打开文件失败: %w", err)
	}
	defer file.Close()

	// 获取文件信息
	fileInfo, err := file.Stat()
	if err != nil {
		return nil, fmt.Errorf("获取文件信息失败: %w", err)
	}

	// 创建 multipart writer
	body := &bytes.Buffer{}
	writer := multipart.NewWriter(body)

	// 添加文件字段
	part, err := writer.CreateFormFile("file", filepath.Base(filePath))
	if err != nil {
		return nil, fmt.Errorf("创建文件字段失败: %w", err)
	}

	_, err = io.Copy(part, file)
	if err != nil {
		return nil, fmt.Errorf("复制文件内容失败: %w", err)
	}

	// 添加可选参数
	if bucket != "" {
		writer.WriteField("bucket", bucket)
	}
	if key != "" {
		writer.WriteField("key", key)
	}

	// 关闭 writer
	writer.Close()

	// 创建 HTTP 请求
	req, err := http.NewRequest("POST", "http://localhost:7075/api/public/upload", body)
	if err != nil {
		return nil, fmt.Errorf("创建请求失败: %w", err)
	}

	req.Header.Set("Content-Type", writer.FormDataContentType())

	// 发送请求
	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("发送请求失败: %w", err)
	}
	defer resp.Body.Close()

	// 读取响应
	var uploadResp UploadResponse
	if err := json.NewDecoder(resp.Body).Decode(&uploadResp); err != nil {
		return nil, fmt.Errorf("解析响应失败: %w", err)
	}

	if uploadResp.Code != 200 {
		return nil, fmt.Errorf("上传失败: %s", uploadResp.Message)
	}

	return &uploadResp.Data, nil
}

// UploadFileWithTypeLimit 上传文件（带文件类型限制）
func UploadFileWithTypeLimit(filePath string, allowedTypes []string) (*UploadResult, error) {
	// 打开文件
	file, err := os.Open(filePath)
	if err != nil {
		return nil, fmt.Errorf("打开文件失败: %w", err)
	}
	defer file.Close()

	// 创建 multipart writer
	body := &bytes.Buffer{}
	writer := multipart.NewWriter(body)

	// 添加文件字段
	part, err := writer.CreateFormFile("file", filepath.Base(filePath))
	if err != nil {
		return nil, fmt.Errorf("创建文件字段失败: %w", err)
	}

	_, err = io.Copy(part, file)
	if err != nil {
		return nil, fmt.Errorf("复制文件内容失败: %w", err)
	}

	writer.Close()

	// 构建 URL，添加文件类型限制参数
	url := "http://localhost:7075/api/public/upload"
	if len(allowedTypes) > 0 {
		url += "?"
		for i, t := range allowedTypes {
			if i > 0 {
				url += "&"
			}
			url += "allowedTypes=" + t
		}
	}

	// 创建 HTTP 请求
	req, err := http.NewRequest("POST", url, body)
	if err != nil {
		return nil, fmt.Errorf("创建请求失败: %w", err)
	}

	req.Header.Set("Content-Type", writer.FormDataContentType())

	// 发送请求
	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("发送请求失败: %w", err)
	}
	defer resp.Body.Close()

	// 读取响应
	var uploadResp UploadResponse
	if err := json.NewDecoder(resp.Body).Decode(&uploadResp); err != nil {
		return nil, fmt.Errorf("解析响应失败: %w", err)
	}

	if uploadResp.Code != 200 {
		return nil, fmt.Errorf("上传失败: %s", uploadResp.Message)
	}

	return &uploadResp.Data, nil
}

// 使用示例
func main() {
	// 基础上传
	result, err := UploadFile("/path/to/file.jpg", "default", "my-files/example.jpg")
	if err != nil {
		fmt.Printf("上传失败: %v\n", err)
		return
	}
	fmt.Printf("上传成功，文件URL: %s\n", result.URL)

	// 带文件类型限制的上传
	result2, err := UploadFileWithTypeLimit("/path/to/image.png", []string{"jpg", "png"})
	if err != nil {
		fmt.Printf("上传失败: %v\n", err)
		return
	}
