type UploadResult struct {
	Key      string `json:"key"`
	Bucket   string `json:"bucket"`
	Filename string `json:"filename"`
	Size     int64  `json:"size"`
	URL      string `json:"url"`
}

type UploadResponse struct {
	Code    int          `json:"code"`
	Message string       `json:"message"`
	Data    UploadResult `json:"data"`
}

// UploadFileWithResty 使用 go-resty 上传文件
func UploadFileWithResty(filePath string, bucket string, key string) (*UploadResult, error) {
	client := resty.New()

	var resp UploadResponse

	_, err := client.R().
		SetFile("file", filePath).
		SetFormData(map[string]string{
			"bucket": bucket,
			"key":    key,
		}).
		SetResult(&resp).
		Post("http://localhost:7075/api/public/upload")

	if err != nil {
		return nil, fmt.Errorf("上传失败: %w", err)
	}

	if resp.Code != 200 {
		return nil, fmt.Errorf("上传失败: %s", resp.Message)
	}

	return &resp.Data, nil
}

func main() {
	result, err := UploadFileWithResty("/path/to/file.jpg", "default", "my-files/example.jpg")
	if err != nil {
		fmt.Printf("上传失败: %v\n", err)
		return
	}
	fmt.Printf("上传成功，文件URL: %s\n", result.URL)
}

