// 文件上传服务
define FileUploadService {
  // 上传文件
  rpc UploadFile(UploadFileRequest) returns (UploadFileResponse) {
    option (google.api.http) = {
      post: "/api/public/upload"
      body: "*"
    };
  }
}

// 上传文件请求
message UploadFileRequest {
  bytes file_content = 1;  // 文件内容
  string filename = 2;      // 文件名
  string bucket = 3;        // 存储桶名称（可选）
  string key = 4;           // 文件存储路径（可选）
  repeated string allowed_types = 5; // 允许的文件类型（可选）
}

// 上传文件响应
message UploadFileResponse {
  int32 code = 1;
  string message = 2;
  FileData data = 3;
}

// 文件数据
message FileData {
  string key = 1;
  string bucket = 2;
  string filename = 3;
  int64 size = 4;
  string url = 5;
}

